" === Real Project Code Snippets ===

" Table: ZPURCHASE_REQUEST (SE11 or ADT)
" Fields: REQUEST_ID (NUMC 10, key), REQUESTER (UNAME),
"         AMOUNT (CURR 15,2), BUDGET_CODE (CHAR 10),
"         STATUS (CHAR 10), LAST_CHANGED (TIMESTAMP)

" CDS with child association
define root view entity ZI_PurchaseRequest3
  as select from zpurchase_request
  association [0..*] to ZI_PurchaseItem3 as _Items
    on $projection.RequestId = _Items.RequestId
{
  key request_id   as RequestId,
      requester    as Requester,
      amount       as Amount,
      budget_code  as BudgetCode,
      status       as Status,
      last_changed as LastChangedAt,
      _Items
}

" BDEF with actions and draft
managed implementation in class ZBP_PurchReq3 unique;
define behavior for ZI_PurchaseRequest3 alias PurchReq
persistent table zpurchase_request lock master
draft table zdraft_purchreq3 etag master LastChangedAt
{
  create; update;
  field ( mandatory ) Requester, Amount, BudgetCode;
  field ( readonly )  RequestId, Status;
  validation validateBudget on save { field Amount, BudgetCode; }
  action submitForApproval result [1] $self;
  action approve           result [1] $self;
  action reject            result [1] $self;
  draft action Edit; draft action Activate;
  draft action Discard; draft action Resume;
}

" Real challenge fix: COALESCE for missing budget master
SELECT SINGLE COALESCE( approved_limit, 0 )
  FROM zbudget_master
  WHERE budget_code = @ls-BudgetCode
  INTO @DATA(lv_limit).
IF lv_limit = 0.
  " No budget defined - block request
  APPEND VALUE #( %key = ls-%key ) TO failed-purchreq.
ENDIF.

